@st.cache_data
def generate_sample_data():
    import numpy as np
    return pd.DataFrame({
        'date': pd.date_range('2024-01-01', periods=100),
        'value': np.random.randn(100).cumsum(),
        'category': np.random.choice(['A', 'B', 'C'], 100)
    })

data = generate_sample_data()

